#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;
const int M = 5e5 + 5;
int n, m, ans = 0;
vector<int> e[N], b[M];
int in[N], topo[N], dp[N];

bool toposort()
{
	int t = 0;
	priority_queue<int, vector<int>, greater<int> > q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(i);
	while(!q.empty())
	{
		int u = q.top();
		q.pop();
		topo[++t] = u;
		for(int v : e[u])
		{
			in[v]--;
			if(!in[v]) q.push(v);
		}
	}
	return t == n;
}

bool toposort2()
{
	int t = 0;
	queue<int> q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(i);
	while(!q.empty())
	{
		int u = q.front();
		q.pop();
		topo[++t] = u;
		for(int v : e[u])
		{
			in[v]--;
			if(!in[v]) q.push(v);
		}
	}
	return t == n;
}

void build(int x)
{
	for(int i = 1; i <= n; i++)
		in[i] = 0, e[i].clear();
	for(int i = 1; i <= x; i++)
	{
		int l = b[i].size();
		for(int j = 1; j < l; j++)
		{
			e[b[i][j - 1]].push_back(b[i][j]);
			in[b[i][j]]++;
		}
	}
}

bool check(int x)
{
	build(x);
	return toposort2();
}

int main()
{
	cin >> n >> m;
	for(int i = 1; i <= m; i++)
	{
		int mi;
		cin >> mi;
		for(int j = 1; j <= mi; j++)
		{
			int bi;
			cin >> bi;
			b[i].push_back(bi);
		}
	}
	int l = 0, r = m + 1;
	while(l + 1 < r)
	{
		int mid = (l + r) >> 1;
		if(check(mid)) l = mid;
		else r = mid;
	}
	build(l);
	toposort();
	for(int i = 1; i <= n; i++)
		cout << topo[i] << ' ';
	return 0;
}
